def flush_all(self) -> bool:
        """写回所有脏页"""
        with self.lock:
            success = True
            for frame in self.frames.values():
                if frame.dirty and frame.page_id is not None:
                    if not self._write_page_to_disk(frame):
                        success = False
                        if self.logger:
                            self.logger.error(f"Failed to flush page {frame.page_id}")
            return success
